index 965777002052..c30a849f30cc 100644
--- a/llvm/lib/Transforms/Vectorize/VPlanUtils.h
+++ b/llvm/lib/Transforms/Vectorize/VPlanUtils.h
@@ -43,6 +43,10 @@ inline bool isUniformAfterVectorization(const VPValue *VPV) {
     return true;
   const VPRecipeBase *Def = VPV->getDefiningRecipe();
   assert(Def && "Must have definition for value defined inside vector region");
+  // Values produced by VPExpandSCEVRecipe are expanded as scalars and are
+  // uniform across lanes.
+  if (isa<VPExpandSCEVRecipe>(Def))
+    return true;
